    "audit_result": {
      "property_id": "PROP-baseauction-inv-032",
      "classification": "potential-vulnerability",
      "code_path": "src/BaseAuction.sol::performUpkeep::L305-370",
      "proof_trace": "checkUpkeep calls _getAssetPrice(asset, false) which returns an isPriceValid flag without reverting, while performUpkeep calls _getAssetPrice(assetOut, true) and _getAssetPrice(asset, true) which REVERT on stale or zero price (L315, L342). If any price becomes stale between checkUpkeep (off-chain) and performUpkeep (on-chain), the entire batch reverts \u2014 all eligible assets are blocked despite being valid at check time. Additionally, performUpkeep uses snapshot amounts from checkUpkeep with fresh prices for the minAuctionSize check (L344\u2013347), so a price drop between check and perform can also cause a revert.",
      "attack_scenario": "A transient oracle staleness event (heartbeat gap or brief feed outage) for the assetOut between checkUpkeep simulation and performUpkeep execution causes performUpkeep to revert at L315 with StaleFeedData, blocking all eligible assets in the batch; fee aggregator balances accumulate and auction opportunities are missed until the oracle recovers.",
      "checklist_id": "PROP-baseauction-inv-032"
    },
    "text": "checkUpkeep and performUpkeep must agree: assets marked eligible by check must be processable by perform.",
    "assertion": "forall asset in checkUpkeep.eligible: performUpkeep(asset) does not revert due to state mismatch",
    "covers": "SG-002",
    "severity": "MEDIUM",
    "type": "invariant"
  }
}

